    if (isBirthday) {
        speed -= 5;
    }

    // Determine which ticket to give
    if (speed <= 60) {
        return 0; // No ticket
    } else if (speed <= 80) {
        return 1; // Small ticket
    } else {
        return 2; // Big ticket
    }
}

